def evaluate_application(
    application,
    data_type,
    data_size,
    classical_baseline_accuracy
):
    # Data type scoring
    if data_type == 'quantum':
        data_score = 1.0
        data_rationale = 'Quantum data is ideal for quantum ML'
    elif data_type == 'structured':
        data_score = 0.5
        data_rationale = 'May benefit if structure matches quantum features'
    else:  # unstructured
        data_score = 0.2
        data_rationale = 'Unstructured data unlikely to benefit'

    # Size scoring (need enough data for learning)
    if data_size < 100:
        size_score = 0.3
        size_rationale = 'Too few samples for reliable learning'
    elif data_size < 1000:
        size_score = 0.7
        size_rationale = 'Adequate for variational approaches'
    else:
        size_score = 1.0
        size_rationale = 'Good sample size'

    # Classical baseline scoring
    if classical_baseline_accuracy > 0.95:
        baseline_score = 0.2
        baseline_rationale = 'Classical already very good - hard to improve'
    elif classical_baseline_accuracy > 0.85:
        baseline_score = 0.5
        baseline_rationale = 'Room for improvement'
    else:
        baseline_score = 0.8
        baseline_rationale = 'Classical struggles - potential opportunity'

    # Overall score
    overall_score = (data_score + size_score + baseline_score) / 3

    if overall_score > 0.7:
        recommendation = 'Promising - worth investigating'
    elif overall_score > 0.4:
        recommendation = 'Uncertain - proceed with caution'
    else:
        recommendation = 'Not recommended for quantum ML'

    return {
        'application': application,
        'scores': {
            'data_type': {'score': data_score, 'reason': data_rationale},
            'data_size': {'score': size_score, 'reason': size_rationale},
            'baseline': {'score': baseline_score, 'reason': baseline_rationale}
        },
        'overall_score': overall_score,
        'recommendation': recommendation
    }

result = evaluate_application(
    'Molecular property prediction',
    'quantum',
    500,
    0.78
)
print(f"Application: {result['application']}")
print(f"Overall score: {result['overall_score']:.2f}")
print(f"Recommendation: {result['recommendation']}")
